const event = $input.first().json;
const d = event.d ?? event;

if (event.t !== 'MESSAGE_CREATE' && event.type !== 0) {
  return [{ json: { skip: true } }];
}
// DMs have no guild_id; channel_type 1 = DM
if (d.guild_id) {
  return [{ json: { skip: true } }];
}
if (d.author?.bot || d.webhook_id) {
  return [{ json: { skip: true } }];
}
const content = String(d.content || '').trim();
if (!content) {
  return [{ json: { skip: true } }];
}
return [{ json: {
  skip: false,
  content,
  author_id: String(d.author?.id || ''),
  channel_id: String(d.channel_id || '')
} }];

const msg = $('Filter DM Message').item.json;
const authorId = String(msg.author_id || '');
const rows = $input.all();
if (!rows.length) {
  return [{ json: { devVerified: false } }];
}
const member = rows.find(r => String(r.json.discord_id || '').trim() === authorId);
return [{ json: {
  devVerified: !!member,
  author_id: authorId,
  channel_id: msg.channel_id,
  content: msg.content
} }];

const raw = $input.first().json;
const prs = Array.isArray(raw) ? raw : [];
const stripped = prs.map(pr => ({
  state: pr.state || 'open',
  labels: Array.isArray(pr.labels) ? pr.labels.map(l => ({ name: String(l.name || '') })) : []
}));
return [{ json: stripped }];

const githubData = $('Strip GitHub Fields').item.json;
const jiraData = $input.first().json;

const features = {};
let hasData = false;

const addFeature = key => {
  if (!features[key]) features[key] = { open_prs: 0, closed_prs: 0, open_issues: 0, closed_issues: 0 };
};

const sanitizeLabel = raw => String(raw || '')
  .toLowerCase()
  .replace(/[^a-z0-9 \-]/g, '')
  .trim()
  .slice(0, 50) || 'general';

const prs = Array.isArray(githubData) ? githubData : [];
for (const pr of prs.slice(0, 30)) {
  if (!pr || typeof pr !== 'object') continue;
  const labels = (pr.labels || []).map(l => sanitizeLabel(l.name)).filter(l => l && l !== 'general');
  const area = labels.length > 0 ? labels[0] : 'general';
  addFeature(area);
  if (pr.state === 'open') features[area].open_prs++;
  else features[area].closed_prs++;
  hasData = true;
}

const jiraIssues = Array.isArray(jiraData?.issues) ? jiraData.issues : [];
for (const issue of jiraIssues.slice(0, 30)) {
  if (!issue || typeof issue !== 'object') continue;
  const fields = issue.fields || {};
  const labels = Array.isArray(fields.labels) ? fields.labels.map(l => sanitizeLabel(l)).filter(Boolean) : [];
  const components = Array.isArray(fields.components) ? fields.components.map(c => sanitizeLabel(c.name)).filter(Boolean) : [];
  const area = labels[0] || components[0] || 'general';
  addFeature(area);
  const statusName = String(fields.status?.name || '').toLowerCase();
  if (statusName === 'done' || statusName === 'closed' || statusName === 'resolved') {
    features[area].closed_issues++;
  } else {
    features[area].open_issues++;
  }
  hasData = true;
}

const lines = [];
if (!hasData) {
  lines.push('No supplementary signal data available from GitHub or Jira at this time.');
} else {
  for (const [area, counts] of Object.entries(features)) {
    const parts = [];
    if (counts.open_prs > 0)      parts.push(counts.open_prs + ' open PR(s)');
    if (counts.closed_prs > 0)    parts.push(counts.closed_prs + ' merged/closed PR(s)');
    if (counts.open_issues > 0)   parts.push(counts.open_issues + ' open ticket(s)');
    if (counts.closed_issues > 0) parts.push(counts.closed_issues + ' resolved ticket(s)');
    if (parts.length > 0) lines.push('- ' + area + ': ' + parts.join(', '));
  }
}

return [{ json: {
  signal_summary: lines.join('\n'),
  has_signals: hasData,
  dev_question: $('Verify Developer').item.json.content,
  channel_id: $('Verify Developer').item.json.channel_id
} }];

const ctx = $input.first().json;

const lmUrl = String($env.LLM_BASE_URL || '');
const host = lmUrl.replace(/^https?:\/\//, '').split(/[/:?#]/)[0];
const isPrivate =
  host === 'localhost' ||
  /^127\./.test(host) ||
  /^10\./.test(host) ||
  /^192\.168\./.test(host) ||
  /^172\.(1[6-9]|2[0-9]|3[01])\./.test(host) ||
  /^100\.(6[4-9]|[7-9]\d|1[01]\d|12[0-7])\./.test(host) ||
  /^169\.254\./.test(host) ||
  /^\[?::1\]?$/.test(host) ||
  /^\[?fe80:/i.test(host) ||
  /\.(internal|local|corp|lan)$/i.test(host) ||
  !host.includes('.');
if (!isPrivate) {
  throw new Error('SC-11 VIOLATION: LLM_BASE_URL must be a private/local endpoint.');
}

// Strip control chars and template delimiters from the question
const safeQuestion = String(ctx.dev_question || '')
  .replace(/[\x00-\x1F\x7F<>|]/g, ' ')
  .trim()
  .slice(0, 1000);

const signalText = ctx.has_signals
  ? ctx.signal_summary
  : 'No activity data is currently available from GitHub or Jira.';

const systemPrompt = [
  'You are a project coordinator answering a developer question about the project.',
  '',
  'ABSOLUTE RULES:',
  '1. Provide project-level and feature-level context only.',
  '2. Do not name, identify, or attribute work to any specific individual teammate.',
  '3. If asked who is assigned to something, provide the feature-area context without naming the person.',
  '4. Base your answer ONLY on the project context provided. Do not invent or assume status.',
  '5. Keep it concise and factual.',
  '6. Return ONLY the reply text. No preamble, no meta-commentary.'
].join('\n');

const userMsg = [
  'Developer question: ' + safeQuestion,
  '',
  'Current project context:',
  signalText
].join('\n');

return [{ json: {
  model: $env.LLM_MODEL,
  temperature: 0.3,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: userMsg }
  ],
  _channel_id: ctx.channel_id
} }];

const response = $input.first().json;
const content = String(response.choices?.[0]?.message?.content ?? '').trim();

if (!content) {
  return [{ json: { clean: false, reply: '', channel_id: $('Assemble Context').item.json.channel_id } }];
}

const rosterRows = $('Fetch Roster').all();

const normalize = s => String(s).normalize('NFKD').replace(/[^\x00-\x7F]/g, '').toLowerCase();
const contentNorm = normalize(content);

const hasWordBoundary = (haystack, needle) => {
  let idx = 0;
  while ((idx = haystack.indexOf(needle, idx)) !== -1) {
    const pre  = idx === 0 || !/[a-z0-9]/.test(haystack[idx - 1]);
    const post = idx + needle.length >= haystack.length || !/[a-z0-9]/.test(haystack[idx + needle.length]);
    if (pre && post) return true;
    idx++;
  }
  return false;
};

let violation = false;

for (const row of rosterRows) {
  const name = normalize(row.json.name || '');
  if (!name.trim()) continue;
  const parts = name.split(/\s+/).filter(p => p.length > 0);
  for (const part of parts) {
    if (hasWordBoundary(contentNorm, part)) { violation = true; break; }
  }
  if (violation) break;
}

if (!violation) {
  const ids = rosterRows.map(r => String(r.json.discord_id || '').trim());
  const digitsOnly = content.replace(/\D/g, '');
  const snowflakes = contentNorm.match(/\b\d{17,19}\b/g) || [];
  for (const id of ids) {
    if (!id) continue;
    if (snowflakes.includes(id) || (id.length >= 17 && digitsOnly.includes(id))) {
      violation = true; break;
    }
  }
}

return [{ json: {
  clean: !violation,
  reply: content,
  channel_id: $('Assemble Context').item.json.channel_id
} }];
